<span class="line">        <span class="token keyword">const</span> offer <span class="token operator">=</span> <span class="token keyword">await</span> peerConn<span class="token punctuation">.</span><span class="token function">createOffer</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
